public class RemoveDuplicates {
    public static void main(String[] args) {
        int[] arr = {1, 2, 3, 4, 5, 5, 6, 7, 8, 9};
        int[] result = removeDuplicates(arr);
        System.out.println(Arrays.toString(result));
